async function doRegister() {
  const rawName  = document.getElementById('a-name')?.value||'';
  const rawEmail = document.getElementById('a-email')?.value||'';
  const pass     = document.getElementById('a-pass')?.value||'';
  const name     = rawName.trim();
  const email    = rawEmail.trim().toLowerCase();

  if(!name||!email||!pass) return renderAuth('register',{text:'Preencha todos os campos'});
  if(!isValidEmail(email))  return renderAuth('register',{text:'Formato de e-mail inválido'});
  const pwCheck = checkPasswordStrength(pass);
  if(!pwCheck.ok) return renderAuth('register',{text:pwCheck.msg});

  const btn = document.querySelector('#auth-card .btn-primary');
  if(btn) { btn.disabled=true; btn.textContent='Criando conta...'; }

  try {
    const cred = await fbAuth.createUserWithEmailAndPassword(email, pass);
    await cred.user.updateProfile({ displayName: name });
    // Save profile to Firestore
    await fbDb.collection('users').doc(cred.user.uid).set({
      name, email,
      trialStart: Date.now(),
      createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      plan: 'trial',
      role: 'user',
      lastLogin: firebase.firestore.FieldValue.serverTimestamp(),
    });
    secLog('register', email);
    // onAuthStateChanged will fire and call renderApp()
  } catch(err) {
    if(btn) { btn.disabled=false; btn.textContent='Criar conta'; }
    const msgs = {
      'auth/email-already-in-use': 'E-mail já cadastrado.',
      'auth/invalid-email':        'Formato de e-mail inválido.',
      'auth/weak-password':        'Senha muito fraca (mínimo 6 caracteres).',
    };
    renderAuth('register', {text: msgs[err.code] || 'Erro ao criar conta: ' + err.message});
  }
}

async function doLogin() {
  const rawEmail = document.getElementById('a-email')?.value||'';
  const pass     = document.getElementById('a-pass')?.value||'';
  const email    = rawEmail.trim().toLowerCase();

  if(!email||!pass) return renderAuth('login',{text:'Preencha e-mail e senha'});
  if(!isValidEmail(email)) return renderAuth('login',{text:'Formato de e-mail inválido'});

  const btn = document.querySelector('#auth-card .btn-primary');
  if(btn) { btn.disabled=true; btn.textContent='Entrando...'; }

  try {
    await fbAuth.signInWithEmailAndPassword(email, pass);
    secLog('login_ok', email);
    // onAuthStateChanged will fire and call renderApp()
  } catch(err) {
    if(btn) { btn.disabled=false; btn.textContent='Entrar'; }
    const msgs = {
      'auth/user-not-found':   'E-mail ou senha inválidos.',
      'auth/wrong-password':   'E-mail ou senha inválidos.',
      'auth/invalid-credential': 'E-mail ou senha inválidos.',
      'auth/too-many-requests':'Muitas tentativas. Aguarde alguns minutos.',
      'auth/invalid-email':    'Formato de e-mail inválido.',
    };
    renderAuth('login', {text: msgs[err.code] || 'Erro ao entrar: ' + err.message});
  }
}

async function doGoogleLogin() {
  try {
    let result;
    try {
      result = await fbAuth.signInWithPopup(googleProvider);
    } catch(popupErr) {
      // Popup blocked or internal error — fall back to redirect
      if(popupErr.code === 'auth/popup-blocked' ||
         popupErr.code === 'auth/internal-error' ||
         popupErr.code === 'auth/popup-closed-by-user') {
        if(popupErr.code !== 'auth/popup-closed-by-user') {
          await fbAuth.signInWithRedirect(googleProvider);
        }
        return;
      }
      throw popupErr;
    }
    const fbUser = result.user;
    const docRef = fbDb.collection('users').doc(fbUser.uid);
    const snap   = await docRef.get();
    if(!snap.exists) {
      await docRef.set({
        name:        fbUser.displayName || fbUser.email.split('@')[0],
        email:       fbUser.email,
        trialStart:  Date.now(),
        createdAt:   firebase.firestore.FieldValue.serverTimestamp(),
        plan:        'trial',
        googleLinked: fbUser.email,
      });
    } else {
      await docRef.set({ googleLinked: fbUser.email, lastLogin: firebase.firestore.FieldValue.serverTimestamp() }, { merge: true });
    }
    secLog('google_login', fbUser.email);
  } catch(err) {
    if(err.code !== 'auth/popup-closed-by-user') {
      showToast('Erro no login Google: ' + (err.message || err.code));
    }
  }
}

/* Handle redirect result on page load */
fbAuth.getRedirectResult().then(async result => {
  if (result && result.user) {
    const fbUser = result.user;
    const docRef = fbDb.collection('users').doc(fbUser.uid);
    const snap   = await docRef.get().catch(() => null);
    if (snap && !snap.exists) {
      await docRef.set({
        name:         fbUser.displayName || fbUser.email.split('@')[0],
        email:        fbUser.email,
        trialStart:   Date.now(),
        createdAt:    firebase.firestore.FieldValue.serverTimestamp(),
        plan:         'trial',
        googleLinked: fbUser.email,
      }).catch(() => {});
    }
  }
}).catch(err => {
  if (err && err.code === 'auth/unauthorized-domain') {
    console.error('[Auth] Dominio nao autorizado:', window.location.hostname);
  } else if (err && err.code && err.code !== 'auth/popup-closed-by-user') {
    console.error('[Auth] getRedirectResult error:', err.code, err.message);
  }
});

async function doGithubLogin() {
  try {
    const result = await fbAuth.signInWithPopup(githubProvider);
    const fbUser = result.user;
    // Create profile doc if first time
    const docRef = fbDb.collection('users').doc(fbUser.uid);
    const snap = await docRef.get();
    if(!snap.exists) {
      await docRef.set({
        name: fbUser.displayName || fbUser.email.split('@')[0],
        email: fbUser.email,
        trialStart: Date.now(),
        createdAt: firebase.firestore.FieldValue.serverTimestamp(),
        plan: 'trial',
        githubLinked: fbUser.email,
      });
    } else {
      await docRef.set({ githubLinked: fbUser.email }, { merge: true });
    }
    secLog('github_login', fbUser.email);
    // onAuthStateChanged fires → renderApp()
  } catch(err) {
    if(err.code !== 'auth/popup-closed-by-user') {
      showToast('Erro no login GitHub: ' + (err.message || err.code));
    }
  }
}

async function doLogout() {
  try {
    await fbAuth.signOut();
    session = null;
    // onAuthStateChanged fires → renderLanding()
  } catch(e) {
    session = null;
    renderAuth('login');
  }
}

function getInitials(name) {
  return name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
}


function buildSidebarNav() {
  const mods = modulesLoad();
  const _prof = session?.user?.uid ? (stGet(session.user.uid+'_profile')||{}) : {};
  const _isAdmin = _prof.role==='admin' || _prof.isAdmin;
  const navLabels = {
    home:'News', dashboard:'Dashboard', positions:'Pool de Liquidez',
    copytrading:'Copy Trading', options:'Mercado de Opções', wallet:'Carteira',
    finance:'Finanças', settings:'Configurações', p2p:'P2P Cripto',
    dp:'Depto. Pessoal', dpjp:'人事部 Japão', relatoriosbr:'Relatórios BR', relatoriosjp:'Relatórios JP',
    imovelvendas:'Vendas', imovellocation:'Locação',
    consorcios:'Posições', comunidade:'Comunidade'
  };

  const groups = [
    {
      label: 'PRINCIPAL',
      items: [
        { show: mods.dashboard !== false, mod: 'dashboard', label: navLabels.dashboard },
        { show: mods.comunidade !== false, mod: 'comunidade', label: navLabels.comunidade }
      ]
    },
    {
      label: 'DEFI',
      items: [
        { show: mods.positions !== false, mod: 'positions', label: navLabels.positions },
        { show: mods.options !== false, mod: 'options', label: navLabels.options },
        { show: mods.p2p !== false, mod: 'p2p', label: navLabels.p2p }
      ]
    },
    {
      label: 'FOREX & STOCKS',
      items: [
        { show: mods.wallet !== false, mod: 'wallet', label: navLabels.wallet },
        { show: mods.copytrading !== false, mod: 'copytrading', label: navLabels.copytrading }
      ]
    },
    {
      label: 'CONTABIL',
      items: [
        { show: mods.finance !== false, mod: 'finance', label: navLabels.finance },
        { show: mods.dp !== false, mod: 'dp', label: navLabels.dp },
        { show: mods.dpjp !== false, mod: 'dpjp', label: navLabels.dpjp },
        { show: mods.relatoriosbr !== false, mod: 'relatoriosbr', label: navLabels.relatoriosbr },
        { show: mods.relatoriosjp !== false, mod: 'relatoriosjp', label: navLabels.relatoriosjp }
      ]
    },
    {
      label: 'IMÓVEIS',
      items: [
        { show: mods.imovelvendas !== false, mod: 'imovelvendas', label: navLabels.imovelvendas },
        { show: mods.imovellocation !== false, mod: 'imovellocation', label: navLabels.imovellocation }
      ]
    },
    {
      label: 'CONSÓRCIOS',
      items: [
        { show: mods.consorcios !== false, mod: 'consorcios', label: navLabels.consorcios }
      ]
    },
    {
      label: 'Conta',
      items: [
        { show: true, mod: 'settings', label: navLabels.settings }
      ]
    },
    {
      label: 'ADMIN',
      adminOnly: true,
      items: [
        { show: _isAdmin, mod: '__admin__', label: '🛡️ Painel Admin', adminLink: true }
      ]
    }
  ];

  return groups.map((group, idx) => {
    const hasItems = group.items.some(i => i.show);
    if(!hasItems) return '';
    
    const items = group.items.filter(i => i.show).map(i =>
      i.adminLink
        ? `<button class="nav-item" onclick="openAdminPanel()" style="color:#39ff8a;font-weight:700"><span class="nav-icon" style="font-size:15px">🛡️</span><span class="nav-label">Painel Admin</span></button>`
        : navItem(i.mod, '', i.label)
    ).join('');
    return `
      <div class="sidebar-group">
        <button class="sidebar-group-toggle" onclick="toggleSidebarGroup(event, ${idx})">
          <span class="accordion-arrow">▶</span>
          <span>${group.label}</span>
        </button>
        <div class="sidebar-group-items collapsed" data-group="${idx}">
          ${items}
        </div>
      </div>
    `;
  }).join('');
}


/* ── Admin panel opener ── */
function openAdminPanel() {
  // Open admin.html in same tab (or new tab if preferred)
  window.open('admin.html', '_blank');
}

